import { expectDiagnostics } from "@typespec/compiler/testing";
import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { describe, it, beforeEach } from "vitest";
import { Tester } from "../testing/test-host.js";
import { uiRouteAuthoringRule } from "../rules/ui-route-authoring.rule.js";

// UiCommand, Stay, Pop, Push, Reload are exported from the library under the State namespace.
// The tester already does `using State` so they're available as UiCommand<T,N>, Stay, Pop etc.
const UI_MODELS = ``;

describe("@uiRoute", () => {
  // T016_01
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_ui_route
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_01
  it("T016_01: @uiRoute namespace with path inside @component Ui — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        @uiRoute(#{ path: "/tasks" })
        namespace TaskListRoute {}
      }
    `);
  });

  // T016_02
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_02
  it("T016_02: @uiRoute namespace without path inside @component Ui — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        @uiRoute
        namespace ResumeOverlay {}
      }
    `);
  });

  // T016_03
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_03
  it("T016_03: @uiRoute on an operation — TypeSpec extern dec rejects", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        @uiRoute(#{ path: "/tasks" })
        op task_list(): void;
      }
    `);
    expectDiagnostics(diagnostics, { code: "decorator-wrong-target" });
  });

  // T016_04
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_04
  it("T016_04: @uiRoute namespace at global scope — invalid-namespace-nesting", async () => {
    const runner = await Tester.createInstance();
    const diagnostics = await runner.diagnose(`
      @uiRoute(#{ path: "/" })
      namespace Home {}
    `);
    expectDiagnostics(diagnostics, {
      code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
      message: /uiRoute/,
    });
  });

  // T016_05
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_05
  it("T016_05: nested @uiRoute inside parent @uiRoute — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        @uiRoute(#{ path: "/tasks" })
        namespace TaskList {
          @uiRoute
          namespace FilterPanel {}
        }
      }
    `);
  });

  // T016_06: action op returning UiCommand — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_06
  it("T016_06: action op inside @uiRoute returning UiCommand — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        ${UI_MODELS}
        @uiRoute(#{ path: "/tasks" })
        namespace TaskListRoute {
          op on_mount(): UiCommand;
        }
      }
    `);
  });

  // T016_12: Pop op with clean @doc (no parent route name) — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_12
  it("T016_12: Pop action op without naming parent route in @doc — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Ui })
      namespace Components.MyUi {
        ${UI_MODELS}
        @uiRoute(#{ path: "/tasks" })
        namespace TaskListRoute {
          @doc("Closes this overlay.")
          op on_close(): Pop;
        }
      }
    `);
  });

  // T016_13: mount action op with @calls on stream op — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_13
  it("T016_13: mount action op with @calls on stream op — zero diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      namespace Components {
        @component(#{ type: ComponentType.Service })
        namespace TaskService {
          namespace Http {
            op StreamTask(): string;
          }
        }

        @component(#{ type: ComponentType.Ui })
        @dependsOn([Components.TaskService])
        namespace MyUi {
          ${UI_MODELS}
          @uiRoute(#{ path: "/tasks/:id" })
          namespace TaskDetailRoute {
            @calls([Components.TaskService.Http.StreamTask])
            op on_mount(): UiCommand;
          }
        }
      }
    `);
  });
});

describe("@uiRoute linting (T016_07, T016_08, T016_09)", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, uiRouteAuthoringRule, "@a10n/blueprint-typespec");
  });

  // T016_07: nested @uiRoute with path — fires path-on-modal
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_07
  it("T016_07: nested @uiRoute with path — fires pathOnModal", async () => {
    await ruleTester
      .expect(`
        @component(#{ type: ComponentType.Ui })
        namespace Components.MyUi {
          ${UI_MODELS}
          @uiRoute(#{ path: "/tasks" })
          namespace TaskList {
            @uiRoute(#{ path: "/tasks/filter" })
            namespace FilterPanel {
              op on_apply(): UiCommand;
            }
            op on_mount(): UiCommand;
          }
        }
      `)
      .toEmitDiagnostics({
        code: "@a10n/blueprint-typespec/ui-route-authoring",
        message: /FilterPanel/,
      });
  });

  // T016_08: @calls targeting a Service Http op from a @uiRoute action — zero diagnostics
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_08
  // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_calls:Products.A10nBlueprintEngine.Features.CallsWhitelist.ui_action_calls:must
  it("T016_08: @calls targeting regular op inside @uiRoute parent — zero diagnostics", async () => {
    await ruleTester
      .expect(`
        namespace Components {
          @component(#{ type: ComponentType.Service })
          namespace TaskService {
            namespace Http {
              op load_tasks(): string;
            }
          }

          @component(#{ type: ComponentType.Ui })
          @dependsOn([Components.TaskService])
          namespace MyUi {
            ${UI_MODELS}
            @uiRoute(#{ path: "/tasks" })
            namespace TaskList {
              @calls([Components.TaskService.Http.load_tasks])
              op on_mount(): UiCommand;
            }
          }
        }
      `)
      .toBeValid();
  });

  // T016_09: action op returning void — fires nav-not-return-type
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T016.T016_09
  it("T016_09: action op returning void — fires navNotReturnType", async () => {
    await ruleTester
      .expect(`
        @component(#{ type: ComponentType.Ui })
        namespace Components.MyUi {
          @uiRoute(#{ path: "/tasks" })
          namespace TaskListRoute {
            op on_cancel(): void;
          }
        }
      `)
      .toEmitDiagnostics({
        code: "@a10n/blueprint-typespec/ui-route-authoring",
        message: /on_cancel/,
      });
  });
});
